code = """import json
import ast

# Load data
reviews = locals()['var_function-call-7326245742234594102']
# reviews might be a list or a dict with 'result' key?
# checking the tool output format: it returns a list of records directly in the storage key variable if it's not a file path.
# The previous tool output showed "The result is: [...]". So it's a list.
# But sometimes it might be a file path if large.
# The tool output preview says "The result is: [...]" and is small.
# Wait, checking the instructions: "If a tool result is large, ... storage entry will be the .json file path".
# The preview in the chat shows the content, so it's likely the variable holds the data.
# However, usually I should check if it's a string (file path) or list.
# Based on the preview, it looks like it fits in memory. But for robustness, I'll check.

def load_data(data_var):
    if isinstance(data_var, str) and data_var.endswith('.json'):
        with open(data_var, 'r') as f:
            return json.load(f)
    return data_var

reviews_data = load_data(reviews)
businesses_data = load_data(locals()['var_function-call-16520081600014218463'])

# 1. Get reviewed business IDs (normalized to businessid_ prefix)
# business_ref format: "businessref_X"
# business_id format: "businessid_X"
# We need to match X.
reviewed_ids = set()
for r in reviews_data:
    ref = r['business_ref']
    if ref and ref.startswith('businessref_'):
        # Convert businessref_X to businessid_X
        bid = 'businessid_' + ref.split('_')[1]
        reviewed_ids.add(bid)

# 2. Identify businesses with parking
parking_business_ids = set()

for b in businesses_data:
    bid = b.get('business_id')
    attrs = b.get('attributes')
    
    if not attrs or attrs == "None":
        continue
        
    # Check Bike Parking
    # Attributes values are strings in the example: "True", "False"
    bike_parking = False
    if 'BikeParking' in attrs and attrs['BikeParking'] == 'True':
        bike_parking = True
        
    # Check Business Parking
    business_parking = False
    if 'BusinessParking' in attrs:
        bp_val = attrs['BusinessParking']
        if bp_val == 'True':
            business_parking = True
        elif isinstance(bp_val, str) and bp_val.startswith('{'):
            try:
                bp_dict = ast.literal_eval(bp_val)
                # If any value in the dict is True, we assume parking is available?
                # Usually keys are 'garage', 'street', 'lot', 'valet', 'validated'.
                # If any is True, they have parking.
                if any(bp_dict.values()):
                    business_parking = True
            except:
                pass
    
    if bike_parking or business_parking:
        parking_business_ids.add(bid)

# 3. Intersection
result_ids = parking_business_ids.intersection(reviewed_ids)
count = len(result_ids)

print("__RESULT__:")
print(count)"""

